def evaluate(model: nn.Module, loader: DataLoader, criterion: nn.Module, device: torch.device):
    model.eval()
    total_loss = 0.0
    total = 0
    correct = 0

    with torch.no_grad():
        for x, y in loader:
            x = x.to(device, non_blocking=True)
            y = y.to(device, non_blocking=True)

            logits = model(x)
            loss = criterion(logits, y)

            total_loss += loss.item() * x.size(0)
            preds = logits.argmax(dim=1)
            correct += (preds == y).sum().item()
            total += x.size(0)

    return total_loss / max(total, 1), correct / max(total, 1)


def train_one_epoch(model: nn.Module, loader: DataLoader, criterion: nn.Module, optimizer, device: torch.device):
    model.train()
    total_loss = 0.0
    total = 0
    correct = 0

    for x, y in loader:
        x = x.to(device, non_blocking=True)
        y = y.to(device, non_blocking=True)

        optimizer.zero_grad(set_to_none=True)
        logits = model(x)
        loss = criterion(logits, y)
        loss.backward()
        optimizer.step()

        total_loss += loss.item() * x.size(0)
        preds = logits.argmax(dim=1)
        correct += (preds == y).sum().item()
        total += x.size(0)

    return total_loss / max(total, 1), correct / max(total, 1)


def save_checkpoint(path: str, model: nn.Module, classes, model_name: str, epoch: int, best_val_acc: float):
    payload: Dict[str, Any] = {
        "model_name": model_name,
        "epoch": epoch,
        "best_val_acc": best_val_acc,
        "class_to_idx": classes,
        "state_dict": model.state_dict(),
    }
    torch.save(payload, path)


